const { DynamoDBClient, UpdateItemCommand } = require("@aws-sdk/client-dynamodb");
const https = require("https");
const http = require("http");
const { URL } = require("url");

const ddb = new DynamoDBClient({});

const TABLE_NAME = process.env.TABLE_NAME;
const PAYMENT_API_URL = process.env.PAYMENT_API_URL;
const PAYMENT_API_KEY = process.env.PAYMENT_API_KEY || "";
const HTTP_TIMEOUT_MS = Number(process.env.HTTP_TIMEOUT_MS || 5000);
const MAX_CONCURRENCY = Math.max(1, Number(process.env.MAX_CONCURRENCY || 10));

function sleep(ms) {
  return new Promise((r) => setTimeout(r, ms));
}

function requestJson(urlStr, { method = "POST", headers = {}, body = null, timeoutMs = HTTP_TIMEOUT_MS } = {}) {
  return new Promise((resolve, reject) => {
    const url = new URL(urlStr);
    const isHttps = url.protocol === "https:";
    const lib = isHttps ? https : http;

    const payload = body == null ? null : Buffer.from(typeof body === "string" ? body : JSON.stringify(body));
    const req = lib.request(
      {
        protocol: url.protocol,
        hostname: url.hostname,
        port: url.port || (isHttps ? 443 : 80),
        path: url.pathname + url.search,
        method,
        headers: {
          "content-type": "application/json",
          ...(payload ? { "content-length": payload.length } : {}),
          ...headers,
        },
        timeout: timeoutMs,
      },
      (res) => {
        let data = "";
        res.setEncoding("utf8");
        res.on("data", (chunk) => (data += chunk));
        res.on("end", () => {
          const statusCode = res.statusCode || 0;
          let parsed = null;
          try {
            parsed = data ? JSON.parse(data) : null;
          } catch (_) {
            parsed = data;
          }
          resolve({ statusCode, headers: res.headers, body: parsed, rawBody: data });
        });
      }
    );

    req.on("timeout", () => {
      req.destroy(new Error("Request timeout"));
    });
    req.on("error", reject);

    if (payload) req.write(payload);
    req.end();
  });
}

async function updateOrder(orderId, updates) {
  if (!TABLE_NAME) throw new Error("TABLE_NAME env var is required");
  const now = new Date().toISOString();

  const exprNames = { "#updatedAt": "updatedAt" };
  const exprValues = { ":updatedAt": { S: now } };
  const setParts = ["#updatedAt = :updatedAt"];

  for (const [k, v] of Object.entries(updates || {})) {
    const nameKey = `#${k}`;
    const valueKey = `:${k}`;
    exprNames[nameKey] = k;

    if (v === null || v === undefined) {
      exprValues[valueKey] = { NULL: true };
    } else if (typeof v === "string") {
      exprValues[valueKey] = { S: v };
    } else if (typeof v === "number") {
      exprValues[valueKey] = { N: String(v) };
    } else if (typeof v === "boolean") {
      exprValues[valueKey] = { BOOL: v };
    } else {
      exprValues[valueKey] = { S: JSON.stringify(v) };
    }

    setParts.push(`${nameKey} = ${valueKey}`);
  }

  const cmd = new UpdateItemCommand({
    TableName: TABLE_NAME,
    Key: { orderId: { S: String(orderId) } },
    UpdateExpression: "SET " + setParts.join(", "),
    ExpressionAttributeNames: exprNames,
    ExpressionAttributeValues: exprValues,
  });

  await ddb.send(cmd);
}

async function callPaymentApi(order) {
  if (!PAYMENT_API_URL) throw new Error("PAYMENT_API_URL env var is required");

  const headers = {};
  if (PAYMENT_API_KEY) headers["authorization"] = `Bearer ${PAYMENT_API_KEY}`;

  const res = await requestJson(PAYMENT_API_URL, {
    method: "POST",
    headers,
    body: {
      orderId: order.orderId,
      amount: order.amount,
      currency: order.currency,
      customerId: order.customerId,
      paymentMethod: order.paymentMethod,
      metadata: order.metadata,
    },
  });

  return res;
}

async function processRecord(record) {
  let msg;
  try {
    msg = JSON.parse(record.body);
  } catch (err) {
    console.error("Invalid JSON in SQS message body", { messageId: record.messageId, err });
    return;
  }

  const order = msg.order || msg;
  const orderId = order.orderId || order.id;
  if (!orderId) {
    console.error("Missing orderId", { messageId: record.messageId, body: record.body });
    return;
  }

  try {
    await updateOrder(orderId, { status: "PAYMENT_PROCESSING" });
  } catch (err) {
    console.error("DynamoDB update failed (PAYMENT_PROCESSING)", { orderId, err });
  }

  let paymentRes;
  try {
    paymentRes = await callPaymentApi(order);
  } catch (err) {
    console.error("Payment API call failed", { orderId, err });
    try {
      await updateOrder(orderId, { status: "PAYMENT_ERROR", paymentError: String(err && err.message ? err.message : err) });
    } catch (e2) {
      console.error("DynamoDB update failed (PAYMENT_ERROR)", { orderId, err: e2 });
    }
    return;
  }

  const ok = paymentRes && paymentRes.statusCode >= 200 && paymentRes.statusCode < 300;
  const paymentId =
    paymentRes && paymentRes.body && typeof paymentRes.body === "object"
      ? paymentRes.body.paymentId || paymentRes.body.id
      : undefined;

  if (!ok) {
    console.error("Payment API non-2xx response", { orderId, statusCode: paymentRes.statusCode, body: paymentRes.body });
    try {
      await updateOrder(orderId, {
        status: "PAYMENT_DECLINED",
        paymentStatusCode: paymentRes.statusCode,
        paymentResponse: paymentRes.body,
      });
    } catch (err) {
      console.error("DynamoDB update failed (PAYMENT_DECLINED)", { orderId, err });
    }
    return;
  }

  try {
    await updateOrder(orderId, {
      status: "PAID",
      paymentId: paymentId ? String(paymentId) : undefined,
      paymentResponse: paymentRes.body,
    });
  } catch (err) {
    console.error("DynamoDB update failed (PAID)", { orderId, err });
  }
}

async function runWithConcurrency(items, limit, worker) {
  let idx = 0;
  const n = items.length;
  const workers = new Array(Math.min(limit, n)).fill(0).map(async () => {
    while (true) {
      const i = idx++;
      if (i >= n) return;
      try {
        await worker(items[i]);
      } catch (err) {
        console.error("Unhandled worker error", { err });
      }
    }
  });
  await Promise.all(workers);
}

exports.handler = async (event) => {
  const records = (event && event.Records) || [];
  if (!records.length) return;

  const start = Date.now();
  await runWithConcurrency(records, MAX_CONCURRENCY, processRecord);

  const ms = Date.now() - start;
  console.log("Batch processed", { recordCount: records.length, durationMs: ms, maxConcurrency: MAX_CONCURRENCY });

  await sleep(0);
};